INSERT INTO `expense_categories` VALUES (1,1,NULL,'2.1','ແຜນປະເມີນລາຍຈ່າຍບໍລິຫານປົກກະຕິ',1,'AB',NULL,NULL,NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(2,1,1,'2.1.1','ບໍລິຫານສັງລວມ',1,'AB','ຫົວໜ່ວຍ/ເດືອນ','ຈ/ນ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(3,1,1,'2.1.2','ບຳລຸງຮັກສາ, ສ້ອມແປງ ແລະ ຕິດຕັ້ງ',2,'AB','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(4,1,1,'2.1.3','ສ້ອມແປງ ແລະ ປັບປຸງອາຄານຫ້ອງຮຽນ',3,'AB','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(5,1,1,'2.1.4','ສ້ອມແປງພາຫານະ',4,'ABC','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນ','ຈຳນວນຄັ້ງ','2026-05-19 07:27:26','2026-05-19 07:27:26'),(6,1,1,'2.1.5','ຊື້ເຄື່ອງຈັກ, ວັດຖຸອຸປະກອນ',5,'ABC','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນ','ຈຳນວນຄັ້ງ','2026-05-19 07:27:26','2026-05-19 07:27:26'),(7,1,1,'2.1.6','ຄ່າປະກັນໄພພາຫະນະ',6,'ABC','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນ','ຈຳນວນຄັ້ງ','2026-05-19 07:27:26','2026-05-19 07:27:26'),(8,1,1,'2.1.7','ລາຍຈ່າຍໄປວຽກທາງການ',7,'ABC','ອັດຕາ','ຈຳນວນຄັ້ງ','ຈຳນວນຄົນ','2026-05-19 07:27:26','2026-05-19 07:27:26'),(9,1,1,'2.1.8','ປົກປັກຮັກສາ ແລະ ອານາໄມອາຄານ, ສະຖານທີ່',8,'AB','ຫົວໜ່ວຍ/ເດືອນ','ຈ/ນ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(10,1,1,'2.1.9','ວຽກງານກິດຈະກຳນັກສຶກສາ',9,'AB','ຫົວໜ່ວຍ/ເດືອນ','ຈຳນວນ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(11,1,1,'2.1.10','ລາຍຈ່າຍກອງປະຊຸມ, ສຳມະນາ ແລະ ຝຶກອົບຮົມ',10,'AB',NULL,NULL,NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(12,1,11,'2.1.10.1','ລາຍຈ່າຍກອງປະຊຸມ',1,'AB','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນຄັ້ງ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(13,1,11,'2.1.10.2','ລາຍຈ່າຍສຳມະນາ',2,'AB','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນຄັ້ງ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(14,1,11,'2.1.10.3','ລາຍຈ່າຍຝຶກອົບຮົມ',3,'AB','ລາຄາຕໍ່ໜ່ວຍ','ຈຳນວນຄັ້ງ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(15,1,1,'2.1.11','ລາຍຈ່າຍບໍລິຫານປົກກະຕິອື່ນໆ',11,'AB','ຕໍ່ເດືອນ (ກີບ)','ຈ/ນ',NULL,'2026-05-19 07:27:26','2026-05-19 07:27:26'),(16,1,NULL,'2.2','ແຜນປະເມີນລາຍຈ່າຍປັບປຸງ ແລະ ສົ່ງເສີມວິຊາການ',2,'AB',NULL,NULL,NULL,'2026-05-19 07:27:26','2026-05-19 07